{
  "name": "OpsPilot",
  "description": "An autonomous multi-agent operations prototype that simulates reading inputs (Slack/Email), classifying tasks, and executing actions like generating PRDs or emails using Gemini 2.0."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AgentRole {
  INPUT = 'INPUT_AGENT',
  CLASSIFIER = 'CLASSIFIER_AGENT',
  DECISION = 'DECISION_AGENT',
  EXECUTION = 'EXECUTION_AGENT',
  MEMORY = 'MEMORY_AGENT'
}

export enum TaskStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED'
}

export enum TaskPriority {
  HIGH = 'HIGH',
  MEDIUM = 'MEDIUM',
  LOW = 'LOW'
}

export enum TaskType {
  ACTION_ITEM = 'ACTION_ITEM',
  QUESTION = 'QUESTION',
  INFORMATIONAL = 'INFORMATIONAL',
  UNKNOWN = 'UNKNOWN'
}

export interface AgentLog {
  id: string;
  timestamp: number;
  agent: AgentRole;
  message: string;
  data?: any; // Structured data snapshot
  step: 'THINKING' | 'ACTION' | 'RESULT';
}

export interface Task {
  id: string;
  source: 'SLACK' | 'GMAIL' | 'NOTION';
  rawContent: string;
  sender: string;
  timestamp: number;
  status: TaskStatus;

  // Classification Results
  type?: TaskType;
  priority?: TaskPriority;
  summary?: string;
  entities?: string[];

  // Decision Results
  nextAction?: string;
  reasoning?: string;

  // Execution Results
  outputContent?: string; // The generated email, PRD, etc.
  outputType?: 'EMAIL' | 'PRD' | 'SUMMARY' | 'NONE';
}

export interface Metric {
  label: string;
  value: string | number;
  change?: number; // percentage
  trend: 'up' | 'down' | 'neutral';
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Task, TaskType, TaskPriority } from "../types";

// Helper to get AI instance safely
const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

/**
 * CLASSIFIER AGENT
 * Analyzes raw text to determine type, priority, and summary.
 */
export const classifyTaskWithGemini = async (rawContent: string, sender: string): Promise<{
  type: TaskType;
  priority: TaskPriority;
  summary: string;
  entities: string[];
}> => {
  try {
    const ai = getAI();
    const schema: Schema = {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: Object.values(TaskType) },
        priority: { type: Type.STRING, enum: Object.values(TaskPriority) },
        summary: { type: Type.STRING },
        entities: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["type", "priority", "summary", "entities"]
    };

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-09-2025", // Using the latest flash model for speed
      contents: `
        You are the 'Task Classifier Agent' for OpsPilot.
        Analyze the following incoming message from ${sender}.

        Message: "${rawContent}"

        Classify it into a Type (ACTION_ITEM, QUESTION, INFORMATIONAL), determine Priority, extract key entities, and provide a one-sentence summary.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");
    return JSON.parse(text);
  } catch (error) {
    console.error("Classifier Agent Error:", error);
    // Fallback in case of API failure
    return {
      type: TaskType.UNKNOWN,
      priority: TaskPriority.MEDIUM,
      summary: "Failed to classify automatically.",
      entities: []
    };
  }
};

/**
 * DECISION AGENT
 * Decides what action to take based on classification.
 */
export const makeDecisionWithGemini = async (task: Task): Promise<{
  action: string;
  reasoning: string;
  outputType: 'EMAIL' | 'PRD' | 'SUMMARY' | 'NONE';
}> => {
  try {
    const ai = getAI();
    const schema: Schema = {
      type: Type.OBJECT,
      properties: {
        action: { type: Type.STRING },
        reasoning: { type: Type.STRING },
        outputType: { type: Type.STRING, enum: ['EMAIL', 'PRD', 'SUMMARY', 'NONE'] }
      },
      required: ["action", "reasoning", "outputType"]
    };

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-09-2025", 
      contents: `
        You are the 'Decision Agent'.

        Context:
        - Task Summary: ${task.summary}
        - Type: ${task.type}
        - Priority: ${task.priority}
        - Sender: ${task.sender}
        - Original Message: "${task.rawContent}"

        Decide the next best action.
        If it's a request for a document, software feature, or specs, action is 'Generate PRD'.
        If it requires a reply, action is 'Draft Email'.
        If it's informational, action is 'Update Knowledge Base'.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");
    return JSON.parse(text);
  } catch (error) {
    console.error("Decision Agent Error:", error);
    return {
      action: "Manual Review Required",
      reasoning: "AI processing failed.",
      outputType: 'NONE'
    };
  }
};

/**
 * EXECUTION AGENT
 * Generates the actual content (Email, PRD, etc.)
 */
export const executeTaskWithGemini = async (task: Task): Promise<string> => {
  try {
    const ai = getAI();

    let prompt = "";
    if (task.outputType === 'PRD') {
      prompt = `Generate a structured Product Requirement Document (PRD) in Markdown based on this request: "${task.rawContent}". Include Problem, Goals, User Stories, and Tech Stack.`;
    } else if (task.outputType === 'EMAIL') {
      prompt = `Draft a professional, concise follow-up email to ${task.sender} regarding: "${task.summary}". Use a helpful tone.`;
    } else {
      prompt = `Generate a detailed summary and actionable bullet points for this content: "${task.rawContent}"`;
    }

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-09-2025", 
      contents: prompt,
    });

    return response.text || "No content generated.";
  } catch (error) {
    console.error("Execution Agent Error:", error);
    return "Error generating content.";
  }
};

import React from 'react';
import { LayoutDashboard, Inbox, FileText, Settings, Activity } from 'lucide-react';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab }) => {
  const menuItems = [
    { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
    { id: 'inbox', icon: Inbox, label: 'Mission Control' },
    { id: 'documents', icon: FileText, label: 'Knowledge Base' },
    { id: 'settings', icon: Settings, label: 'Settings' },
  ];

  return (
    <div className="w-64 bg-ops-card border-r border-slate-700 flex flex-col h-full">
      <div className="p-6 flex items-center gap-3">
        <div className="w-8 h-8 bg-ops-accent rounded-lg flex items-center justify-center">
          <Activity className="text-white w-5 h-5" />
        </div>
        <h1 className="text-xl font-bold tracking-tight text-white">OpsPilot</h1>
      </div>

      <nav className="flex-1 px-4 space-y-2 mt-4">
        {menuItems.map((item) => {
          const Icon = item.icon;
          const isActive = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
                isActive
                  ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20'
                  : 'text-slate-400 hover:bg-slate-700/50 hover:text-slate-200'
              }`}
            >
              <Icon size={20} />
              <span className="font-medium text-sm">{item.label}</span>
            </button>
          );
        })}
      </nav>

      <div className="p-4 border-t border-slate-700">
        <div className="bg-slate-900/50 rounded-lg p-3">
          <p className="text-xs text-slate-500 font-mono mb-1">SYSTEM STATUS</p>
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
            <span className="text-xs text-emerald-400 font-medium">All Systems Operational</span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import { AgentLog, AgentRole } from '../types';
import { Brain, Terminal, Zap, FileOutput, Database, MessageSquare } from 'lucide-react';

interface AgentLogsProps {
  logs: AgentLog[];
}

export const AgentLogs: React.FC<AgentLogsProps> = ({ logs }) => {
  const endRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const getIcon = (agent: AgentRole) => {
    switch (agent) {
      case AgentRole.INPUT: return <MessageSquare size={14} />;
      case AgentRole.CLASSIFIER: return <Brain size={14} />;
      case AgentRole.DECISION: return <Zap size={14} />;
      case AgentRole.EXECUTION: return <FileOutput size={14} />;
      case AgentRole.MEMORY: return <Database size={14} />;
      default: return <Terminal size={14} />;
    }
  };

  const getColor = (agent: AgentRole) => {
    switch (agent) {
      case AgentRole.INPUT: return 'text-purple-400 border-purple-400/30 bg-purple-400/10';
      case AgentRole.CLASSIFIER: return 'text-yellow-400 border-yellow-400/30 bg-yellow-400/10';
      case AgentRole.DECISION: return 'text-blue-400 border-blue-400/30 bg-blue-400/10';
      case AgentRole.EXECUTION: return 'text-emerald-400 border-emerald-400/30 bg-emerald-400/10';
      case AgentRole.MEMORY: return 'text-pink-400 border-pink-400/30 bg-pink-400/10';
      default: return 'text-slate-400 border-slate-400/30';
    }
  };

  return (
    <div className="flex flex-col h-full bg-black/40 rounded-xl overflow-hidden border border-slate-700/50 backdrop-blur-sm">
      <div className="px-4 py-3 bg-slate-900/80 border-b border-slate-700 flex justify-between items-center">
        <div className="flex items-center gap-2 text-slate-400">
          <Terminal size={16} />
          <span className="text-xs font-mono font-bold uppercase tracking-wider">Agent Live Feed</span>
        </div>
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-slate-600"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-slate-600"></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 font-mono text-sm">
        {logs.length === 0 && (
          <div className="text-slate-600 text-center mt-10 italic">Waiting for incoming signals...</div>
        )}

        {logs.map((log) => (
          <div key={log.id} className="animate-fade-in flex gap-3 group">
             <div className="flex-shrink-0 mt-0.5">
               <div className={`w-6 h-6 rounded flex items-center justify-center border ${getColor(log.agent)}`}>
                 {getIcon(log.agent)}
               </div>
             </div>
             <div className="flex-1 min-w-0">
               <div className="flex items-center gap-2 mb-1">
                 <span className={`text-xs font-bold ${getColor(log.agent).split(' ')[0]}`}>
                   {log.agent}
                 </span>
                 <span className="text-[10px] text-slate-500">
                   {new Date(log.timestamp).toLocaleTimeString()}
                 </span>
               </div>
               <p className="text-slate-300 break-words leading-relaxed">
                 {log.message}
               </p>
               {log.data && (
                 <div className="mt-2 p-2 bg-slate-900 rounded border border-slate-800 text-xs text-slate-400 overflow-x-auto">
                   <pre>{JSON.stringify(log.data, null, 2)}</pre>
                 </div>
               )}
             </div>
          </div>
        ))}
        <div ref={endRef} />
      </div>
    </div>
  );
};

import React from 'react';
import { CheckCircle, Clock, Zap, Target } from 'lucide-react';
import { Metric } from '../types';

interface StatsProps {
  metrics: Metric[];
}

export const DashboardStats: React.FC<StatsProps> = ({ metrics }) => {
  const getIcon = (label: string) => {
    if (label.includes('Success')) return <CheckCircle className="text-emerald-400" size={20} />;
    if (label.includes('Time')) return <Clock className="text-blue-400" size={20} />;
    if (label.includes('Autonomy')) return <Zap className="text-yellow-400" size={20} />;
    return <Target className="text-purple-400" size={20} />;
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
      {metrics.map((metric, idx) => (
        <div key={idx} className="bg-ops-card border border-slate-700/50 p-4 rounded-xl shadow-sm">
          <div className="flex justify-between items-start mb-2">
            <span className="text-slate-400 text-sm font-medium">{metric.label}</span>
            <div className="p-2 bg-slate-800 rounded-lg">
              {getIcon(metric.label)}
            </div>
          </div>
          <div className="flex items-baseline gap-2">
            <span className="text-2xl font-bold text-white">{metric.value}</span>
            {metric.change !== undefined && (
              <span className={`text-xs font-medium ${metric.trend === 'up' ? 'text-emerald-400' : 'text-red-400'}`}>
                {metric.trend === 'up' ? '↑' : '↓'} {Math.abs(metric.change)}%
              </span>
            )}
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { AgentLogs } from './components/AgentLogs';
import { DashboardStats } from './components/DashboardStats';
import { 
  Task, AgentLog, AgentRole, TaskStatus, TaskType, Metric 
} from './types';
import { classifyTaskWithGemini, makeDecisionWithGemini, executeTaskWithGemini } from './services/geminiService';
import { Plus, Play, RotateCcw, FileText, Check, Bot, AlertTriangle } from 'lucide-react';

const MOCK_METRICS: Metric[] = [
  { label: 'Task Success Rate', value: '98.5%', change: 2.1, trend: 'up' },
  { label: 'Avg. Response Time', value: '1.2s', change: 12, trend: 'up' },
  { label: 'Autonomy Score', value: '92/100', change: 5, trend: 'up' },
  { label: 'Actions Executed', value: 342, change: 8, trend: 'up' },
];

const INITIAL_TASK: Task = {
  id: 'task-1',
  source: 'SLACK',
  rawContent: "Hey OpsPilot, we need a PRD for the new 'Dark Mode' feature for the mobile app. It needs to support system preferences and have a toggle in settings. Priority is High.",
  sender: 'Sarah (Product Lead)',
  timestamp: Date.now(),
  status: TaskStatus.PENDING
};

export default function App() {
  const [activeTab, setActiveTab] = useState('inbox');
  const [tasks, setTasks] = useState<Task[]>([]);
  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [logs, setLogs] = useState<AgentLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  useEffect(() => {
    if (!process.env.API_KEY) {
      setApiKeyMissing(true);
    }
  }, []);

  const addLog = (agent: AgentRole, message: string, step: 'THINKING' | 'ACTION' | 'RESULT', data?: any) => {
    const newLog: AgentLog = {
      id: Math.random().toString(36).substring(7),
      timestamp: Date.now(),
      agent,
      message,
      step,
      data
    };
    setLogs(prev => [...prev, newLog]);
  };

  const handleSimulateIncoming = () => {
    const newTask = { ...INITIAL_TASK, id: `task-${Date.now()}`, timestamp: Date.now() };
    setTasks(prev => [newTask, ...prev]);
    setSelectedTaskId(newTask.id);
    addLog(AgentRole.INPUT, `Received new message from ${newTask.source}`, 'ACTION', { content: newTask.rawContent });
  };

  const processTask = useCallback(async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task || isProcessing) return;

    setIsProcessing(true);
    setLogs([]); // Clear logs for clarity on new run

    // update status
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.PROCESSING } : t));

    try {
      // 1. CLASSIFIER
      addLog(AgentRole.CLASSIFIER, "Analyzing message intent and entities...", 'THINKING');
      const classification = await classifyTaskWithGemini(task.rawContent, task.sender);
      addLog(AgentRole.CLASSIFIER, "Classification complete", 'RESULT', classification);

      const updatedTask = { ...task, ...classification };

      // 2. MEMORY (Simulated)
      addLog(AgentRole.MEMORY, "Checking context and previous constraints...", 'THINKING');
      await new Promise(r => setTimeout(r, 800)); // Visual delay
      addLog(AgentRole.MEMORY, "No conflicting blocking constraints found.", 'RESULT');

      // 3. DECISION
      addLog(AgentRole.DECISION, "Determining optimal execution path...", 'THINKING');
      const decision = await makeDecisionWithGemini(updatedTask);
      addLog(AgentRole.DECISION, `Decision made: ${decision.action}`, 'ACTION', decision);

      const decidedTask = { ...updatedTask, ...decision };

      // 4. EXECUTION
      if (decidedTask.outputType !== 'NONE') {
        addLog(AgentRole.EXECUTION, `Executing action: ${decision.action}...`, 'ACTION');
        const output = await executeTaskWithGemini(decidedTask);
        decidedTask.outputContent = output;
        addLog(AgentRole.EXECUTION, "Content generated successfully", 'RESULT', { preview: output.substring(0, 100) + '...' });
      } else {
        addLog(AgentRole.EXECUTION, "No content generation required. Updating records.", 'ACTION');
      }

      // Finalize
      setTasks(prev => prev.map(t => t.id === taskId ? { ...decidedTask, status: TaskStatus.COMPLETED } : t));
      addLog(AgentRole.MEMORY, "Task lifecycle completed. State updated.", 'RESULT');

    } catch (e) {
      addLog(AgentRole.EXECUTION, "Critical Failure in processing chain", 'RESULT', { error: e });
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.FAILED } : t));
    } finally {
      setIsProcessing(false);
    }
  }, [tasks, isProcessing]);

  const renderContent = () => {
    const selectedTask = tasks.find(t => t.id === selectedTaskId);

    if (activeTab === 'dashboard') {
      return (
        <div className="p-6">
          <h2 className="text-2xl font-bold text-white mb-6">System Overview</h2>
          <DashboardStats metrics={MOCK_METRICS} />

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
             <div className="bg-ops-card border border-slate-700 rounded-xl p-6">
                <h3 className="text-lg font-semibold text-white mb-4">Recent Activity</h3>
                <div className="space-y-4">
                  {[1,2,3].map(i => (
                    <div key={i} className="flex items-center gap-4 p-3 rounded-lg bg-slate-800/50">
                      <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                      <div className="flex-1">
                        <div className="text-sm text-slate-200">Generated Weekly Ops Report</div>
                        <div className="text-xs text-slate-500">2 hours ago • Automated</div>
                      </div>
                    </div>
                  ))}
                </div>
             </div>
             <div className="bg-ops-card border border-slate-700 rounded-xl p-6 flex flex-col items-center justify-center text-center">
                <Bot size={48} className="text-slate-600 mb-4" />
                <h3 className="text-lg font-semibold text-white">System Healthy</h3>
                <p className="text-slate-400 text-sm max-w-xs mt-2">
                  All 5 agents are active and listening to configured channels.
                </p>
             </div>
          </div>
        </div>
      );
    }

    // INBOX & DOCUMENT VIEWS
    return (
      <div className="flex h-full">
        {/* Task List */}
        <div className="w-1/3 border-r border-slate-700 flex flex-col bg-slate-900/50">
          <div className="p-4 border-b border-slate-700 flex justify-between items-center">
            <h2 className="font-semibold text-slate-200">Incoming Signals</h2>
            <button 
              onClick={handleSimulateIncoming}
              className="p-1.5 rounded bg-blue-600 text-white hover:bg-blue-500 transition-colors"
              title="Simulate incoming Slack message"
            >
              <Plus size={16} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto">
            {tasks.length === 0 ? (
               <div className="p-8 text-center text-slate-500 text-sm">
                 No active tasks. <br/> Click '+' to simulate incoming data.
               </div>
            ) : (
              tasks.map(task => (
                <div 
                  key={task.id}
                  onClick={() => setSelectedTaskId(task.id)}
                  className={`p-4 border-b border-slate-800 cursor-pointer hover:bg-slate-800/50 transition-colors ${
                    selectedTaskId === task.id ? 'bg-slate-800 border-l-2 border-l-blue-500' : ''
                  }`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold ${
                      task.source === 'SLACK' ? 'bg-[#4A154B] text-white' : 'bg-red-900/50 text-red-200'
                    }`}>
                      {task.source}
                    </span>
                    <span className="text-xs text-slate-500">{new Date(task.timestamp).toLocaleTimeString()}</span>
                  </div>
                  <h4 className="text-sm font-medium text-slate-200 line-clamp-1 mb-1">
                    {task.summary || "New Incoming Message"}
                  </h4>
                  <p className="text-xs text-slate-400 line-clamp-2">
                    {task.rawContent}
                  </p>
                  <div className="mt-2 flex items-center justify-between">
                     <span className={`text-[10px] px-2 py-0.5 rounded-full border ${
                       task.status === TaskStatus.COMPLETED ? 'border-emerald-500/30 text-emerald-400 bg-emerald-500/10' :
                       task.status === TaskStatus.PROCESSING ? 'border-blue-500/30 text-blue-400 bg-blue-500/10' :
                       'border-slate-600 text-slate-400'
                     }`}>
                       {task.status}
                     </span>
                     {task.priority && (
                       <span className="text-[10px] text-orange-400 font-mono">
                         {task.priority} PRIORITY
                       </span>
                     )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Workspace Area */}
        <div className="flex-1 flex flex-col bg-slate-950">
          {selectedTask ? (
            <div className="flex-1 flex flex-col h-full overflow-hidden">
               {/* Toolbar */}
               <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-ops-card">
                  <div className="flex items-center gap-3">
                     <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold">
                        {selectedTask.sender.charAt(0)}
                     </div>
                     <div>
                        <div className="text-sm font-medium text-white">{selectedTask.sender}</div>
                        <div className="text-xs text-slate-500">via {selectedTask.source}</div>
                     </div>
                  </div>
                  <div className="flex gap-2">
                     <button 
                       onClick={() => processTask(selectedTask.id)}
                       disabled={isProcessing || selectedTask.status === TaskStatus.COMPLETED}
                       className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                         selectedTask.status === TaskStatus.COMPLETED
                         ? 'bg-emerald-600/20 text-emerald-400 cursor-default'
                         : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/20'
                       } disabled:opacity-50 disabled:cursor-not-allowed`}
                     >
                        {isProcessing ? (
                          <RotateCcw className="animate-spin" size={16} />
                        ) : selectedTask.status === TaskStatus.COMPLETED ? (
                          <Check size={16} />
                        ) : (
                          <Play size={16} />
                        )}
