               <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { CheckCircle, Clock, Zap, Target } from 'lucide-react';
import { Metric } from '../types';

interface StatsProps {
  metrics: Metric[];
}

export const DashboardStats: React.FC<StatsProps> = ({ metrics }) => {
  const getIcon = (label: string) => {
    if (label.includes('Success')) return <CheckCircle className="text-emerald-500" size={20} />;
    if (label.includes('Time')) return <Clock className="text-blue-500" size={20} />;
    if (label.includes('Autonomy')) return <Zap className="text-amber-500" size={20} />;
    return <Target className="text-purple-500" size={20} />;
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
      {metrics.map((metric, idx) => (
        <div key={idx} className="bg-ops-card border border-ops-border p-4 rounded-xl shadow-sm hover:shadow-md transition-shadow">
          <div className="flex justify-between items-start mb-2">
            <span className="text-ops-muted text-sm font-medium">{metric.label}</span>
            <div className="p-2 bg-ops-bg rounded-lg">
              {getIcon(metric.label)}
            </div>
          </div>
          <div className="flex items-baseline gap-2">
            <span className="text-2xl font-bold text-ops-text">{metric.value}</span>
            {metric.change !== undefined && (
              <span className={`text-xs font-medium ${metric.trend === 'up' ? 'text-emerald-500' : 'text-red-500'}`}>
                {metric.trend === 'up' ? '↑' : '↓'} {Math.abs(metric.change)}%
              </span>
            )}
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import { AgentLog, AgentRole } from '../types';
import { Brain, Terminal, Zap, FileOutput, Database, MessageSquare } from 'lucide-react';

interface AgentLogsProps {
  logs: AgentLog[];
}

export const AgentLogs: React.FC<AgentLogsProps> = ({ logs }) => {
  const endRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const getIcon = (agent: AgentRole) => {
    switch (agent) {
      case AgentRole.INPUT: return <MessageSquare size={14} />;
      case AgentRole.CLASSIFIER: return <Brain size={14} />;
      case AgentRole.DECISION: return <Zap size={14} />;
      case AgentRole.EXECUTION: return <FileOutput size={14} />;
      case AgentRole.MEMORY: return <Database size={14} />;
      default: return <Terminal size={14} />;
    }
  };

  // Logs always look best in dark terminal style, so we hardcode some slate-colors here for the inner content
  // but adapt the container border to the theme.
  const getColor = (agent: AgentRole) => {
    switch (agent) {
      case AgentRole.INPUT: return 'text-purple-400 border-purple-400/30 bg-purple-400/10';
      case AgentRole.CLASSIFIER: return 'text-yellow-400 border-yellow-400/30 bg-yellow-400/10';
      case AgentRole.DECISION: return 'text-blue-400 border-blue-400/30 bg-blue-400/10';
      case AgentRole.EXECUTION: return 'text-emerald-400 border-emerald-400/30 bg-emerald-400/10';
      case AgentRole.MEMORY: return 'text-pink-400 border-pink-400/30 bg-pink-400/10';
      default: return 'text-slate-400 border-slate-400/30';
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#0f172a] rounded-xl overflow-hidden border border-ops-border shadow-inner">
      <div className="px-4 py-3 bg-[#1e293b] border-b border-slate-700 flex justify-between items-center">
        <div className="flex items-center gap-2 text-slate-400">
          <Terminal size={16} />
          <span className="text-xs font-mono font-bold uppercase tracking-wider">Agent Live Feed</span>
        </div>
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-slate-600"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-slate-600"></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 font-mono text-sm">
        {logs.length === 0 && (
          <div className="text-slate-600 text-center mt-10 italic">Waiting for incoming signals...</div>
        )}

        {logs.map((log) => (
          <div key={log.id} className="animate-fade-in flex gap-3 group">
             <div className="flex-shrink-0 mt-0.5">
               <div className={`w-6 h-6 rounded flex items-center justify-center border ${getColor(log.agent)}`}>
                 {getIcon(log.agent)}
               </div>
             </div>
             <div className="flex-1 min-w-0">
               <div className="flex items-center gap-2 mb-1">
                 <span className={`text-xs font-bold ${getColor(log.agent).split(' ')[0]}`}>
                   {log.agent}
                 </span>
                 <span className="text-[10px] text-slate-500">
                   {new Date(log.timestamp).toLocaleTimeString()}
                 </span>
               </div>
               <p className="text-slate-300 break-words leading-relaxed">
                 {log.message}
               </p>
               {log.data && (
                 <div className="mt-2 p-2 bg-[#020617] rounded border border-slate-800 text-xs text-slate-400 overflow-x-auto">
                   <pre>{JSON.stringify(log.data, null, 2)}</pre>
                 </div>
               )}
             </div>
          </div>
        ))}
        <div ref={endRef} />
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { AgentLogs } from './components/AgentLogs';
import { DashboardStats } from './components/DashboardStats';
import { 
  Task, AgentLog, AgentRole, TaskStatus, TaskType, Metric 
} from './types';
import { classifyTaskWithGemini, makeDecisionWithGemini, executeTaskWithGemini } from './services/geminiService';
import { Plus, Play, RotateCcw, FileText, Check, Bot, AlertTriangle, Inbox, Sun, Moon, Search, Sliders, Trash2 } from 'lucide-react';

const MOCK_METRICS: Metric[] = [
  { label: 'Task Success Rate', value: '98.5%', change: 2.1, trend: 'up' },
  { label: 'Avg. Response Time', value: '1.2s', change: 12, trend: 'up' },
  { label: 'Autonomy Score', value: '92/100', change: 5, trend: 'up' },
  { label: 'Actions Executed', value: 342, change: 8, trend: 'up' },
];

const INITIAL_TASK: Task = {
  id: 'task-1',
  source: 'SLACK',
  rawContent: "Hey OpsPilot, we need a PRD for the new 'Dark Mode' feature for the mobile app. It needs to support system preferences and have a toggle in settings. Priority is High.",
  sender: 'Sarah (Product Lead)',
  timestamp: Date.now(),
  status: TaskStatus.PENDING
};

export default function App() {
  const [activeTab, setActiveTab] = useState('inbox');
  const [tasks, setTasks] = useState<Task[]>([]);
  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [logs, setLogs] = useState<AgentLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Theme Effect
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'light') {
      root.classList.add('light-theme');
    } else {
      root.classList.remove('light-theme');
    }
  }, [theme]);

  useEffect(() => {
    if (!process.env.API_KEY) {
      setApiKeyMissing(true);
    }
  }, []);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  const addLog = (agent: AgentRole, message: string, step: 'THINKING' | 'ACTION' | 'RESULT', data?: any) => {
    const newLog: AgentLog = {
      id: Math.random().toString(36).substring(7),
      timestamp: Date.now(),
      agent,
      message,
      step,
      data
    };
    setLogs(prev => [...prev, newLog]);
  };

  const handleSimulateIncoming = () => {
    const newTask = { ...INITIAL_TASK, id: `task-${Date.now()}`, timestamp: Date.now() };
    setTasks(prev => [newTask, ...prev]);
    setSelectedTaskId(newTask.id);
    addLog(AgentRole.INPUT, `Received new message from ${newTask.source}`, 'ACTION', { content: newTask.rawContent });
  };

  const clearHistory = () => {
    setTasks([]);
    setLogs([]);
    setSelectedTaskId(null);
  };

  const processTask = useCallback(async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task || isProcessing) return;

    setIsProcessing(true);
    setLogs([]); 
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.PROCESSING } : t));

    try {
      addLog(AgentRole.CLASSIFIER, "Analyzing message intent and entities...", 'THINKING');
      const classification = await classifyTaskWithGemini(task.rawContent, task.sender);
      addLog(AgentRole.CLASSIFIER, "Classification complete", 'RESULT', classification);

      const updatedTask = { ...task, ...classification };

      addLog(AgentRole.MEMORY, "Checking context and previous constraints...", 'THINKING');
      await new Promise(r => setTimeout(r, 800)); 
      addLog(AgentRole.MEMORY, "No conflicting blocking constraints found.", 'RESULT');

      addLog(AgentRole.DECISION, "Determining optimal execution path...", 'THINKING');
      const decision = await makeDecisionWithGemini(updatedTask);
      addLog(AgentRole.DECISION, `Decision made: ${decision.action}`, 'ACTION', decision);

      const decidedTask = { ...updatedTask, ...decision };

      if (decidedTask.outputType !== 'NONE') {
        addLog(AgentRole.EXECUTION, `Executing action: ${decision.action}...`, 'ACTION');
        const output = await executeTaskWithGemini(decidedTask);
        decidedTask.outputContent = output;
        addLog(AgentRole.EXECUTION, "Content generated successfully", 'RESULT', { preview: output.substring(0, 100) + '...' });
      } else {
        addLog(AgentRole.EXECUTION, "No content generation required. Updating records.", 'ACTION');
      }

      setTasks(prev => prev.map(t => t.id === taskId ? { ...decidedTask, status: TaskStatus.COMPLETED } : t));
      addLog(AgentRole.MEMORY, "Task lifecycle completed. State updated.", 'RESULT');

    } catch (e) {
      addLog(AgentRole.EXECUTION, "Critical Failure in processing chain", 'RESULT', { error: e });
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.FAILED } : t));
    } finally {
      setIsProcessing(false);
    }
  }, [tasks, isProcessing]);

  // --- VIEW RENDERERS ---

  const renderDashboard = () => (
    <div className="p-6 h-full overflow-y-auto">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-ops-text">System Overview</h2>
        <div className="bg-ops-card p-1 rounded-lg border border-ops-border flex">
          <button 
            onClick={() => setTheme('light')}
            className={`p-2 rounded-md transition-colors ${theme === 'light' ? 'bg-ops-bg shadow text-ops-accent' : 'text-ops-muted hover:text-ops-text'}`}
          >
            <Sun size={20} />
          </button>
          <button 
            onClick={() => setTheme('dark')}
            className={`p-2 rounded-md transition-colors ${theme === 'dark' ? 'bg-ops-bg shadow text-ops-accent' : 'text-ops-muted hover:text-ops-text'}`}
          >
            <Moon size={20} />
          </button>
        </div>
      </div>

      <DashboardStats metrics={MOCK_METRICS} />

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="bg-ops-card border border-ops-border rounded-xl p-6">
            <h3 className="text-lg font-semibold text-ops-text mb-4">Recent Activity</h3>
            <div className="space-y-4">
              {[1,2,3].map(i => (
                <div key={i} className="flex items-center gap-4 p-3 rounded-lg bg-ops-bg/50">
                  <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                  <div className="flex-1">
                    <div className="text-sm text-ops-text">Generated Weekly Ops Report</div>
                    <div className="text-xs text-ops-muted">2 hours ago • Automated</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="bg-ops-card border border-ops-border rounded-xl p-6 flex flex-col items-center justify-center text-center">
            <Bot size={48} className="text-ops-muted mb-4" />
            <h3 className="text-lg font-semibold text-ops-text">System Healthy</h3>
            <p className="text-ops-muted text-sm max-w-xs mt-2">
              All 5 agents are active and listening to configured channels.
            </p>
          </div>
      </div>
    </div>
  );

  const renderInbox = () => {
    const selectedTask = tasks.find(t => t.id === selectedTaskId);
    return (
      <div className="flex h-full">
        {/* Task List */}
        <div className="w-1/3 border-r border-ops-border flex flex-col bg-ops-bg/50">
          <div className="p-4 border-b border-ops-border flex justify-between items-center bg-ops-card">
            <h2 className="font-semibold text-ops-text">Incoming Signals</h2>
            <button 
              onClick={handleSimulateIncoming}
              className="p-1.5 rounded bg-blue-600 text-white hover:bg-blue-500 transition-colors shadow-lg shadow-blue-500/20"
              title="Simulate incoming Slack message"
            >
              <Plus size={16} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto">
            {tasks.length === 0 ? (
               <div className="p-8 text-center text-ops-muted text-sm flex flex-col items-center gap-2">
                 <Inbox className="opacity-20" size={40} />
                 No active tasks. <br/> Click '+' to simulate incoming data.
               </div>
            ) : (
              tasks.map(task => (
                <div 
                  key={task.id}
                  onClick={() => setSelectedTaskId(task.id)}
                  className={`p-4 border-b border-ops-border cursor-pointer hover:bg-ops-card transition-colors ${
                    selectedTaskId === task.id ? 'bg-ops-card border-l-4 border-l-ops-accent' : ''
                  }`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold ${
                      task.source === 'SLACK' ? 'bg-[#4A154B] text-white' : 'bg-red-500 text-white'
                    }`}>
                      {task.source}
                    </span>
                    <span className="text-xs text-ops-muted">{new Date(task.timestamp).toLocaleTimeString()}</span>
                  </div>
                  <h4 className="text-sm font-medium text-ops-text line-clamp-1 mb-1">
                    {task.summary || "New Incoming Message"}
                  </h4>
                  <p className="text-xs text-ops-muted line-clamp-2">
                    {task.rawContent}
                  </p>
                  <div className="mt-2 flex items-center justify-between">
                     <span className={`text-[10px] px-2 py-0.5 rounded-full border ${
                       task.status === TaskStatus.COMPLETED ? 'border-emerald-500/30 text-emerald-500 bg-emerald-500/10' :
                       task.status === TaskStatus.PROCESSING ? 'border-blue-500/30 text-blue-500 bg-blue-500/10' :
                       'border-ops-border text-ops-muted'
                     }`}>
                       {task.status}
                     </span>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Workspace Area */}
        <div className="flex-1 flex flex-col bg-ops-bg">
          {selectedTask ? (
            <div className="flex-1 flex flex-col h-full overflow-hidden">
               {/* Toolbar */}
               <div className="p-4 border-b border-ops-border flex justify-between items-center bg-ops-card shadow-sm z-10">
                  <div className="flex items-center gap-3">
                     <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold text-white">
                        {selectedTask.sender.charAt(0)}
                     </div>
                     <div>
                        <div className="text-sm font-medium text-ops-text">{selectedTask.sender}</div>
                        <div className="text-xs text-ops-muted">via {selectedTask.source}</div>
                     </div>
                  </div>
                  <div className="flex gap-2">
                     <button 
                       onClick={() => processTask(selectedTask.id)}
                       disabled={isProcessing || selectedTask.status === TaskStatus.COMPLETED}
                       className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                         selectedTask.status === TaskStatus.COMPLETED
                         ? 'bg-emerald-600/10 text-emerald-500 cursor-default border border-emerald-500/20'
                         : 'bg-ops-accent hover:bg-blue-600 text-white shadow-lg shadow-blue-500/20'
                       } disabled:opacity-50 disabled:cursor-not-allowed`}
                     >
                        {isProcessing ? (
                          <RotateCcw className="animate-spin" size={16} />
                        ) : selectedTask.status === TaskStatus.COMPLETED ? (
                          <Check size={16} />
                        ) : (
                          <Play size={16} />
                        )}
                        {selectedTask.status === TaskStatus.COMPLETED ? 'Completed' : isProcessing ? 'Processing...' : 'Auto-Execute'}
                     </button>
                  </div>
               </div>

               {/* Split View: Details & Logs */}
               <div className="flex-1 flex min-h-0">
                  <div className="w-1/2 p-6 overflow-y-auto border-r border-ops-border">
                     <div className="bg-ops-card rounded-lg p-4 mb-6 border border-ops-border shadow-sm">
                        <h5 className="text-xs font-bold text-ops-muted uppercase mb-2">Original Message</h5>
                        <p className="text-ops-text text-sm whitespace-pre-wrap">{selectedTask.rawContent}</p>
                     </div>

                     {selectedTask.outputContent && (
                       <div className="animate-fade-in">
                          <h5 className="text-xs font-bold text-emerald-500 uppercase mb-3 flex items-center gap-2">
                            <FileText size={14} /> Generated Output ({selectedTask.outputType})
                          </h5>
                          <div className="prose prose-sm max-w-none bg-ops-card p-6 rounded-lg border border-emerald-500/20 shadow-inner">
                            <pre className="whitespace-pre-wrap font-sans text-ops-text">
                              {selectedTask.outputContent}
                            </pre>
                          </div>
                       </div>
                     )}
                  </div>

                  {/* Right Panel: Agent Terminal (Always Dark) */}
                  <div className="w-1/2 bg-black/5 p-4 flex flex-col min-h-0">
                     <AgentLogs logs={logs} />
                  </div>
               </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-ops-muted">
               <Inbox size={48} className="mb-4 opacity-20" />
               <p>Select a task to view details or start execution</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderDocuments = () => {
    const documents = tasks.filter(t => t.status === TaskStatus.COMPLETED && t.outputContent);

    return (
      <div className="p-6 h-full overflow-y-auto bg-ops-bg">
        <h2 className="text-2xl font-bold text-ops-text mb-6 flex items-center gap-2">
          <FileText className="text-ops-accent" /> Knowledge Base
        </h2>

        {documents.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-96 text-ops-muted border-2 border-dashed border-ops-border rounded-xl">
             <FileText size={48} className="opacity-20 mb-4" />
             <p>No generated documents yet.</p>
             <p className="text-sm mt-2">Complete tasks in Mission Control to populate this area.</p>
