              >
                <Sun size={16} /> Light
              </button>
              <button 
                onClick={() => setTheme('dark')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-md transition-colors ${theme === 'dark' ? 'bg-slate-700 shadow text-white' : 'text-ops-muted hover:text-ops-text'}`}
              >
                <Moon size={16} /> Dark
              </button>
