}

export enum TaskStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED'
}

export enum TaskPriority {
  HIGH = 'HIGH',
  MEDIUM = 'MEDIUM',
  LOW = 'LOW'
}

export enum TaskType {
  ACTION_ITEM = 'ACTION_ITEM',
  QUESTION = 'QUESTION',
  INFORMATIONAL = 'INFORMATIONAL',
  UNKNOWN = 'UNKNOWN'
}

export interface AgentLog {
  id: string;
