import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Sidebar } from './components/Sidebar';
import { AgentLogs } from './components/AgentLogs';
import { DashboardStats } from './components/DashboardStats';
import { 
  Task, AgentLog, AgentRole, TaskStatus, TaskType, Metric, IntegrationConfig 
} from './types';
import { classifyTaskWithGemini, makeDecisionWithGemini, executeTaskWithGemini } from './services/geminiService';
import { streamService } from './services/streamService';
import { Plus, Play, RotateCcw, FileText, Check, Bot, AlertTriangle, Inbox, Sun, Moon, Search, Sliders, Trash2, Link2, MessageSquare, Mail, Wifi } from 'lucide-react';

const INITIAL_TASK: Task = {
  id: 'task-1',
  source: 'SLACK',
  rawContent: "Hey OpsPilot, we need a PRD for the new 'Dark Mode' feature for the mobile app. It needs to support system preferences and have a toggle in settings. Priority is High.",
  sender: 'Sarah (Product Lead)',
  timestamp: Date.now(),
  status: TaskStatus.PENDING
};

export default function App() {
  const [activeTab, setActiveTab] = useState('inbox');
  const [tasks, setTasks] = useState<Task[]>([INITIAL_TASK]);
  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [logs, setLogs] = useState<AgentLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Integration State
  const [integrations, setIntegrations] = useState<IntegrationConfig[]>([
    { id: 'slack', name: 'Slack', description: 'Listen to #engineering and #product channels.', isConnected: false },
    { id: 'gmail', name: 'Gmail', description: 'Monitor support@ and info@ inboxes.', isConnected: false },
    { id: 'notion', name: 'Notion', description: 'Watch for new pages in Product Workspace.', isConnected: false }
  ]);

  // Theme Effect
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'light') {
      root.classList.add('light-theme');
    } else {
      root.classList.remove('light-theme');
    }
  }, [theme]);

  // API Key Check
  useEffect(() => {
    if (!process.env.API_KEY) {
      setApiKeyMissing(true);
    }
  }, []);

  // Real-time Stream Subscription
  useEffect(() => {
    const unsubscribe = streamService.subscribe((newTask) => {
      setTasks(prev => [newTask, ...prev]);

      // Notify user via a log or toast equivalent
      addLog(AgentRole.INPUT, `Stream Event: New signal from ${newTask.source}`, 'ACTION', { id: newTask.id });
    });
    return () => unsubscribe();
  }, []);

  // Update Stream Service when integrations change
  useEffect(() => {
    integrations.forEach(integration => {
      if (integration.isConnected) {
        streamService.activateConnector(integration.id);
      } else {
        streamService.deactivateConnector(integration.id);
      }
    });
  }, [integrations]);

  // Dynamic Metrics Calculation
  const metrics: Metric[] = useMemo(() => {
    const total = tasks.length;
    if (total === 0) return [
      { label: 'Task Success Rate', value: '0%', trend: 'neutral' },
      { label: 'Avg. Response Time', value: '0s', trend: 'neutral' },
      { label: 'Active Connectors', value: 0, trend: 'neutral' },
      { label: 'Actions Executed', value: 0, trend: 'neutral' },
    ];

    const completed = tasks.filter(t => t.status === TaskStatus.COMPLETED).length;
    const rate = Math.round((completed / total) * 100);
    const activeConnectors = integrations.filter(i => i.isConnected).length;

    return [
      { label: 'Task Success Rate', value: `${rate}%`, change: 2.1, trend: 'up' },
      { label: 'Avg. Response Time', value: '1.2s', change: 12, trend: 'up' }, // Mocked for now, hard to calc without start/end times
      { label: 'Active Connectors', value: activeConnectors, change: activeConnectors > 0 ? 100 : 0, trend: 'up' },
      { label: 'Total Volume', value: total, change: 8, trend: 'up' },
    ];
  }, [tasks, integrations]);


  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  const toggleIntegration = (id: string) => {
    setIntegrations(prev => prev.map(int => 
      int.id === id ? { ...int, isConnected: !int.isConnected, lastSync: Date.now() } : int
    ));
  };

  const addLog = (agent: AgentRole, message: string, step: 'THINKING' | 'ACTION' | 'RESULT', data?: any) => {
    const newLog: AgentLog = {
      id: Math.random().toString(36).substring(7),
      timestamp: Date.now(),
      agent,
      message,
      step,
      data
    };
    setLogs(prev => [...prev, newLog]);
  };

  const handleSimulateIncoming = () => {
    const newTask = { ...INITIAL_TASK, id: `task-${Date.now()}`, timestamp: Date.now() };
    setTasks(prev => [newTask, ...prev]);
    setSelectedTaskId(newTask.id);
    addLog(AgentRole.INPUT, `Received new message from ${newTask.source}`, 'ACTION', { content: newTask.rawContent });
  };

  const clearHistory = () => {
    setTasks([]);
    setLogs([]);
    setSelectedTaskId(null);
  };

  const processTask = useCallback(async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task || isProcessing) return;

    setIsProcessing(true);
    setLogs([]); 
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.PROCESSING } : t));

    try {
      addLog(AgentRole.CLASSIFIER, "Analyzing message intent and entities...", 'THINKING');
      const classification = await classifyTaskWithGemini(task.rawContent, task.sender);
      addLog(AgentRole.CLASSIFIER, "Classification complete", 'RESULT', classification);

      const updatedTask = { ...task, ...classification };

      addLog(AgentRole.MEMORY, "Checking context and previous constraints...", 'THINKING');
      await new Promise(r => setTimeout(r, 800)); 
      addLog(AgentRole.MEMORY, "No conflicting blocking constraints found.", 'RESULT');

      addLog(AgentRole.DECISION, "Determining optimal execution path...", 'THINKING');
      const decision = await makeDecisionWithGemini(updatedTask);
      addLog(AgentRole.DECISION, `Decision made: ${decision.action}`, 'ACTION', decision);

      const decidedTask = { ...updatedTask, ...decision };

      if (decidedTask.outputType !== 'NONE') {
        addLog(AgentRole.EXECUTION, `Executing action: ${decision.action}...`, 'ACTION');
        const output = await executeTaskWithGemini(decidedTask);
        decidedTask.outputContent = output;
        addLog(AgentRole.EXECUTION, "Content generated successfully", 'RESULT', { preview: output.substring(0, 100) + '...' });
      } else {
        addLog(AgentRole.EXECUTION, "No content generation required. Updating records.", 'ACTION');
      }

      setTasks(prev => prev.map(t => t.id === taskId ? { ...decidedTask, status: TaskStatus.COMPLETED } : t));
      addLog(AgentRole.MEMORY, "Task lifecycle completed. State updated.", 'RESULT');

    } catch (e) {
      addLog(AgentRole.EXECUTION, "Critical Failure in processing chain", 'RESULT', { error: e });
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.FAILED } : t));
    } finally {
      setIsProcessing(false);
    }
  }, [tasks, isProcessing]);

  // --- VIEW RENDERERS ---

  const renderDashboard = () => (
    <div className="p-6 h-full overflow-y-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
           <h2 className="text-2xl font-bold text-ops-text">System Overview</h2>
           <p className="text-sm text-ops-muted mt-1 flex items-center gap-2">
             <span className="relative flex h-3 w-3">
               <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${integrations.some(i => i.isConnected) ? 'bg-emerald-500' : 'bg-slate-500'}`}></span>
               <span className={`relative inline-flex rounded-full h-3 w-3 ${integrations.some(i => i.isConnected) ? 'bg-emerald-500' : 'bg-slate-500'}`}></span>
             </span>
             {integrations.some(i => i.isConnected) ? 'Live Data Stream Active' : 'Offline Mode'}
           </p>
        </div>
        <div className="bg-ops-card p-1 rounded-lg border border-ops-border flex">
          <button 
            onClick={() => setTheme('light')}
            className={`p-2 rounded-md transition-colors ${theme === 'light' ? 'bg-ops-bg shadow text-ops-accent' : 'text-ops-muted hover:text-ops-text'}`}
          >
            <Sun size={20} />
          </button>
          <button 
            onClick={() => setTheme('dark')}
            className={`p-2 rounded-md transition-colors ${theme === 'dark' ? 'bg-ops-bg shadow text-ops-accent' : 'text-ops-muted hover:text-ops-text'}`}
          >
            <Moon size={20} />
          </button>
        </div>
      </div>

      <DashboardStats metrics={metrics} />

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="bg-ops-card border border-ops-border rounded-xl p-6">
            <h3 className="text-lg font-semibold text-ops-text mb-4">Recent Activity</h3>
            <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2">
              {tasks.slice(0, 6).map((task, i) => (
                <div key={i} className="flex items-center gap-4 p-3 rounded-lg bg-ops-bg/50 animate-fade-in border border-ops-border/50">
                  <div className={`w-2 h-2 rounded-full ${task.status === TaskStatus.COMPLETED ? 'bg-emerald-500' : 'bg-blue-500'}`}></div>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm text-ops-text font-medium truncate">{task.summary || "Incoming Signal"}</div>
                    <div className="text-xs text-ops-muted flex justify-between">
                       <span>via {task.source}</span>
                       <span>{new Date(task.timestamp).toLocaleTimeString()}</span>
                    </div>
                  </div>
                </div>
              ))}
              {tasks.length === 0 && <div className="text-ops-muted text-center py-4">No recent activity</div>}
            </div>
          </div>
          <div className="bg-ops-card border border-ops-border rounded-xl p-6 flex flex-col items-center justify-center text-center">
            <div className="relative">
              <Bot size={48} className="text-ops-accent mb-4" />
              {isProcessing && <div className="absolute -top-1 -right-1 w-3 h-3 bg-emerald-400 rounded-full animate-pulse border-2 border-ops-card"></div>}
            </div>
            <h3 className="text-lg font-semibold text-ops-text">System Status: {isProcessing ? 'Thinking...' : 'Idle'}</h3>
            <p className="text-ops-muted text-sm max-w-xs mt-2">
              All agents are operational. 
              {integrations.filter(i => i.isConnected).length} active connectors listening for events.
            </p>
            <button 
               onClick={() => setActiveTab('integrations')}
               className="mt-4 text-sm text-ops-accent hover:underline"
            >
              Configure Integrations
            </button>
          </div>
      </div>
    </div>
  );

  const renderInbox = () => {
    const selectedTask = tasks.find(t => t.id === selectedTaskId);
    return (
      <div className="flex h-full">
        {/* Task List */}
        <div className="w-1/3 border-r border-ops-border flex flex-col bg-ops-bg/50">
          <div className="p-4 border-b border-ops-border flex justify-between items-center bg-ops-card">
            <h2 className="font-semibold text-ops-text">Incoming Signals</h2>
            <button 
              onClick={handleSimulateIncoming}
              className="p-1.5 rounded bg-blue-600 text-white hover:bg-blue-500 transition-colors shadow-lg shadow-blue-500/20"
              title="Simulate incoming Slack message"
            >
              <Plus size={16} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto">
            {tasks.length === 0 ? (
               <div className="p-8 text-center text-ops-muted text-sm flex flex-col items-center gap-2">
                 <Inbox className="opacity-20" size={40} />
                 No active tasks. <br/> Click '+' to simulate incoming data.
               </div>
            ) : (
              tasks.map(task => (
                <div 
                  key={task.id}
                  onClick={() => setSelectedTaskId(task.id)}
                  className={`p-4 border-b border-ops-border cursor-pointer hover:bg-ops-card transition-colors ${
                    selectedTaskId === task.id ? 'bg-ops-card border-l-4 border-l-ops-accent' : ''
                  }`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold ${
                      task.source === 'SLACK' ? 'bg-[#4A154B] text-white' : 
                      task.source === 'GMAIL' ? 'bg-red-500 text-white' : 'bg-black text-white border border-slate-700'
                    }`}>
                      {task.source}
                    </span>
                    <span className="text-xs text-ops-muted">{new Date(task.timestamp).toLocaleTimeString()}</span>
                  </div>
                  <h4 className="text-sm font-medium text-ops-text line-clamp-1 mb-1">
                    {task.summary || "New Incoming Message"}
                  </h4>
                  <p className="text-xs text-ops-muted line-clamp-2">
                    {task.rawContent}
                  </p>
                  <div className="mt-2 flex items-center justify-between">
                     <span className={`text-[10px] px-2 py-0.5 rounded-full border ${
                       task.status === TaskStatus.COMPLETED ? 'border-emerald-500/30 text-emerald-500 bg-emerald-500/10' :
                       task.status === TaskStatus.PROCESSING ? 'border-blue-500/30 text-blue-500 bg-blue-500/10' :
                       'border-ops-border text-ops-muted'
                     }`}>
                       {task.status}
                     </span>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Workspace Area */}
        <div className="flex-1 flex flex-col bg-ops-bg">
          {selectedTask ? (
            <div className="flex-1 flex flex-col h-full overflow-hidden">
               {/* Toolbar */}
               <div className="p-4 border-b border-ops-border flex justify-between items-center bg-ops-card shadow-sm z-10">
                  <div className="flex items-center gap-3">
                     <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold text-white">
                        {selectedTask.sender.charAt(0)}
                     </div>
                     <div>
                        <div className="text-sm font-medium text-ops-text">{selectedTask.sender}</div>
                        <div className="text-xs text-ops-muted">via {selectedTask.source}</div>
                     </div>
                  </div>
                  <div className="flex gap-2">
                     <button 
                       onClick={() => processTask(selectedTask.id)}
                       disabled={isProcessing || selectedTask.status === TaskStatus.COMPLETED}
                       className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                         selectedTask.status === TaskStatus.COMPLETED
                         ? 'bg-emerald-600/10 text-emerald-500 cursor-default border border-emerald-500/20'
                         : 'bg-ops-accent hover:bg-blue-600 text-white shadow-lg shadow-blue-500/20'
                       } disabled:opacity-50 disabled:cursor-not-allowed`}
                     >
                        {isProcessing ? (
                          <RotateCcw className="animate-spin" size={16} />
                        ) : selectedTask.status === TaskStatus.COMPLETED ? (
                          <Check size={16} />
                        ) : (
                          <Play size={16} />
                        )}
                        {selectedTask.status === TaskStatus.COMPLETED ? 'Completed' : isProcessing ? 'Processing...' : 'Auto-Execute'}
                     </button>
                  </div>
               </div>

               {/* Split View: Details & Logs */}
               <div className="flex-1 flex min-h-0">
                  <div className="w-1/2 p-6 overflow-y-auto border-r border-ops-border">
                     <div className="bg-ops-card rounded-lg p-4 mb-6 border border-ops-border shadow-sm">
                        <h5 className="text-xs font-bold text-ops-muted uppercase mb-2">Original Message</h5>
                        <p className="text-ops-text text-sm whitespace-pre-wrap">{selectedTask.rawContent}</p>
                     </div>

                     {selectedTask.outputContent && (
                       <div className="animate-fade-in">
                          <h5 className="text-xs font-bold text-emerald-500 uppercase mb-3 flex items-center gap-2">
                            <FileText size={14} /> Generated Output ({selectedTask.outputType})
                          </h5>
                          <div className="prose prose-sm max-w-none bg-ops-card p-6 rounded-lg border border-emerald-500/20 shadow-inner">
                            <pre className="whitespace-pre-wrap font-sans text-ops-text">
                              {selectedTask.outputContent}
                            </pre>
                          </div>
                       </div>
                     )}
                  </div>

                  {/* Right Panel: Agent Terminal (Always Dark) */}
                  <div className="w-1/2 bg-black/5 p-4 flex flex-col min-h-0">
                     <AgentLogs logs={logs} />
                  </div>
               </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-ops-muted">
               <Inbox size={48} className="mb-4 opacity-20" />
               <p>Select a task to view details or start execution</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderDocuments = () => {
    const documents = tasks.filter(t => t.status === TaskStatus.COMPLETED && t.outputContent);

    return (
      <div className="p-6 h-full overflow-y-auto bg-ops-bg">
        <h2 className="text-2xl font-bold text-ops-text mb-6 flex items-center gap-2">
          <FileText className="text-ops-accent" /> Knowledge Base
        </h2>

        {documents.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-96 text-ops-muted border-2 border-dashed border-ops-border rounded-xl">
             <FileText size={48} className="opacity-20 mb-4" />
             <p>No generated documents yet.</p>
             <p className="text-sm mt-2">Complete tasks in Mission Control to populate this area.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {documents.map(doc => (
              <div key={doc.id} className="bg-ops-card border border-ops-border rounded-xl p-6 hover:shadow-lg transition-all group">
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-lg ${
                    doc.outputType === 'PRD' ? 'bg-purple-500/10 text-purple-500' : 
                    doc.outputType === 'EMAIL' ? 'bg-blue-500/10 text-blue-500' : 'bg-emerald-500/10 text-emerald-500'
                  }`}>
                    <FileText size={24} />
                  </div>
                  <span className="text-xs text-ops-muted">{new Date(doc.timestamp).toLocaleDateString()}</span>
                </div>
                <h3 className="font-semibold text-ops-text mb-2 line-clamp-1">{doc.summary || "Untitled Document"}</h3>
                <p className="text-sm text-ops-muted line-clamp-3 mb-4 h-12">
                   {doc.outputContent}
                </p>
                <div className="flex items-center justify-between mt-4 pt-4 border-t border-ops-border">
                  <span className="text-xs font-mono text-ops-muted">{doc.outputType}</span>
                  <button 
                    onClick={() => {
                      setActiveTab('inbox');
                      setSelectedTaskId(doc.id);
                    }}
                    className="text-sm text-ops-accent hover:underline"
                  >
                    View Source
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderIntegrations = () => (
    <div className="p-6 h-full overflow-y-auto bg-ops-bg">
      <h2 className="text-2xl font-bold text-ops-text mb-6 flex items-center gap-2">
        <Link2 className="text-ops-accent" /> Connectors
      </h2>
      <p className="text-ops-muted mb-8 max-w-2xl">
        Connect your external tools to enable the OpsPilot real-time event stream. 
        When enabled, the system will simulate incoming traffic from these sources.
      </p>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {integrations.map((integration) => {
          const Icon = integration.id === 'slack' ? MessageSquare : integration.id === 'gmail' ? Mail : FileText;
          const color = integration.id === 'slack' ? 'text-purple-500' : integration.id === 'gmail' ? 'text-red-500' : 'text-black dark:text-white';

          return (
            <div key={integration.id} className={`bg-ops-card border ${integration.isConnected ? 'border-ops-accent ring-1 ring-ops-accent/50' : 'border-ops-border'} rounded-xl p-6 transition-all shadow-sm hover:shadow-md`}>
              <div className="flex justify-between items-start mb-4">
                 <div className={`p-3 rounded-xl bg-ops-bg border border-ops-border ${color}`}>
                   <Icon size={28} />
                 </div>
                 <div className={`px-2 py-1 rounded text-xs font-bold uppercase tracking-wider ${integration.isConnected ? 'bg-emerald-500/10 text-emerald-500' : 'bg-ops-bg text-ops-muted'}`}>
                   {integration.isConnected ? 'Connected' : 'Offline'}
                 </div>
              </div>
              <h3 className="text-lg font-bold text-ops-text mb-2">{integration.name}</h3>
              <p className="text-sm text-ops-muted h-10 mb-6">{integration.description}</p>

              <button
                onClick={() => toggleIntegration(integration.id)}
                className={`w-full py-2.5 rounded-lg text-sm font-medium transition-all ${
                   integration.isConnected 
                   ? 'bg-red-500/10 text-red-500 hover:bg-red-500/20 border border-red-500/20' 
                   : 'bg-ops-text text-ops-bg hover:opacity-90'
                }`}
              >
                {integration.isConnected ? 'Disconnect' : 'Connect Stream'}
              </button>

              {integration.isConnected && integration.lastSync && (
                <div className="mt-4 flex items-center gap-2 text-xs text-ops-muted justify-center animate-fade-in">
                  <Wifi size={12} className="text-emerald-500" />
                  Streaming live events...
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );

  const renderSettings = () => (
    <div className="p-6 max-w-4xl mx-auto h-full overflow-y-auto">
      <h2 className="text-2xl font-bold text-ops-text mb-8 flex items-center gap-2">
        <Sliders className="text-ops-accent" /> Settings
      </h2>

      <div className="space-y-6">
        {/* Appearance */}
        <section className="bg-ops-card border border-ops-border rounded-xl p-6">
          <h3 className="text-lg font-semibold text-ops-text mb-4">Appearance</h3>
          <div className="flex items-center justify-between">
            <div>
              <p className="font-medium text-ops-text">Interface Theme</p>
              <p className="text-sm text-ops-muted">Select your preferred color scheme.</p>
            </div>
            <div className="bg-ops-bg p-1 rounded-lg border border-ops-border flex">
              <button 
                onClick={() => setTheme('light')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-md transition-colors ${theme === 'light' ? 'bg-white shadow text-black' : 'text-ops-muted hover:text-ops-text'}`}
              >
                <Sun size={16} /> Light
              </button>
              <button 
                onClick={() => setTheme('dark')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-md transition-colors ${theme === 'dark' ? 'bg-slate-700 shadow text-white' : 'text-ops-muted hover:text-ops-text'}`}
              >
                <Moon size={16} /> Dark
              </button>
            </div>
          </div>
        </section>

        {/* Data Management */}
        <section className="bg-ops-card border border-ops-border rounded-xl p-6">
          <h3 className="text-lg font-semibold text-ops-text mb-4">Data Management</h3>
          <div className="flex items-center justify-between">
             <div>
               <p className="font-medium text-ops-text">Clear Session Data</p>
               <p className="text-sm text-ops-muted">Remove all tasks, logs, and generated documents.</p>
             </div>
             <button 
               onClick={clearHistory}
               className="flex items-center gap-2 px-4 py-2 bg-red-500/10 text-red-500 border border-red-500/20 rounded-lg hover:bg-red-500/20 transition-colors"
             >
               <Trash2 size={16} /> Clear All
             </button>
          </div>
        </section>

        {/* API Configuration */}
        <section className="bg-ops-card border border-ops-border rounded-xl p-6">
           <h3 className="text-lg font-semibold text-ops-text mb-4">API Configuration</h3>
           <div className="space-y-4">
             <div>
                <label className="block text-sm font-medium text-ops-text mb-1">Google GenAI API Key</label>
                <div className="flex gap-2">
                   <input 
                     type="password" 
                     value={process.env.API_KEY ? "sk-xxxxxxxxxxxxxxxxxxxxxxxx" : ""}
                     disabled
                     className="flex-1 bg-ops-bg border border-ops-border rounded-lg px-3 py-2 text-ops-muted font-mono text-sm"
                     placeholder="Not configured"
                   />
                   {process.env.API_KEY ? (
                     <span className="flex items-center gap-1 text-emerald-500 text-sm font-medium px-2">
                       <Check size={16} /> Active
                     </span>
                   ) : (
                     <span className="flex items-center gap-1 text-red-500 text-sm font-medium px-2">
                       <AlertTriangle size={16} /> Missing
                     </span>
                   )}
                </div>
                <p className="text-xs text-ops-muted mt-2">
                  Key is injected via environment variables. To change it, update your environment configuration.
                </p>
             </div>
           </div>
        </section>
      </div>
    </div>
  );

  return (
    <div className="flex h-screen bg-ops-bg text-ops-text font-sans overflow-hidden transition-colors duration-300">
      {apiKeyMissing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 p-8 rounded-xl border border-red-500/50 max-w-md text-center shadow-2xl">
            <AlertTriangle className="mx-auto text-red-500 mb-4" size={48} />
            <h2 className="text-xl font-bold text-white mb-2">Missing API Key</h2>
            <p className="text-slate-400 mb-6">
              OpsPilot requires a valid Gemini API Key to function. 
              Please verify your <code>process.env.API_KEY</code> setup.
            </p>
          </div>
        </div>
      )}

      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col min-w-0 bg-ops-bg transition-colors duration-300">
        <header className="h-16 border-b border-ops-border bg-ops-card/50 backdrop-blur flex items-center justify-between px-6 z-10">
          <h2 className="font-semibold text-lg text-ops-text capitalize flex items-center gap-2">
             {activeTab === 'inbox' && <Inbox size={20} className="text-ops-muted" />}
             {activeTab === 'dashboard' && <div className="text-ops-muted"><span className="text-ops-accent">Ops</span>Dashboard</div>}
             {activeTab === 'documents' && <FileText size={20} className="text-ops-muted" />}
             {activeTab === 'integrations' && <Link2 size={20} className="text-ops-muted" />}
             {activeTab === 'settings' && <Sliders size={20} className="text-ops-muted" />}

             {activeTab === 'inbox' ? 'Mission Control' : 
              activeTab === 'documents' ? 'Knowledge Base' : 
              activeTab === 'integrations' ? 'Connectors' :
              activeTab === 'dashboard' ? '' : 'Settings'}
          </h2>
          <div className="flex items-center gap-4">
             <div className="text-xs text-ops-muted font-mono">v0.2.1-beta</div>
             <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-500 to-purple-500 border-2 border-ops-bg shadow-sm"></div>
          </div>
        </header>

        <div className="flex-1 overflow-hidden relative">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'inbox' && renderInbox()}
          {activeTab === 'documents' && renderDocuments()}
          {activeTab === 'integrations' && renderIntegrations()}
          {activeTab === 'settings' && renderSettings()}
        </div>
      </main>
    </div>
  );
}

export enum AgentRole {
  INPUT = 'INPUT_AGENT',
  CLASSIFIER = 'CLASSIFIER_AGENT',
  DECISION = 'DECISION_AGENT',
  EXECUTION = 'EXECUTION_AGENT',
  MEMORY = 'MEMORY_AGENT'
}

export enum TaskStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED'
}

export enum TaskPriority {
  HIGH = 'HIGH',
  MEDIUM = 'MEDIUM',
  LOW = 'LOW'
}

export enum TaskType {
  ACTION_ITEM = 'ACTION_ITEM',
  QUESTION = 'QUESTION',
  INFORMATIONAL = 'INFORMATIONAL',
  UNKNOWN = 'UNKNOWN'
}

export interface AgentLog {
  id: string;
  timestamp: number;
  agent: AgentRole;
  message: string;
  data?: any; // Structured data snapshot
  step: 'THINKING' | 'ACTION' | 'RESULT';
}

export interface Task {
  id: string;
  source: 'SLACK' | 'GMAIL' | 'NOTION';
  rawContent: string;
  sender: string;
  timestamp: number;
  status: TaskStatus;

  // Classification Results
  type?: TaskType;
  priority?: TaskPriority;
  summary?: string;
  entities?: string[];

  // Decision Results
  nextAction?: string;
  reasoning?: string;

  // Execution Results
  outputContent?: string; // The generated email, PRD, etc.
  outputType?: 'EMAIL' | 'PRD' | 'SUMMARY' | 'NONE';
}

export interface Metric {
  label: string;
  value: string | number;
  change?: number; // percentage
  trend: 'up' | 'down' | 'neutral';
}

export interface IntegrationConfig {
  id: 'slack' | 'gmail' | 'notion';
  name: string;
  description: string;
  isConnected: boolean;
  lastSync?: number;
  connectedAccount?: string;
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Sidebar } from './components/Sidebar';
import { AgentLogs } from './components/AgentLogs';
import { DashboardStats } from './components/DashboardStats';
import { 
  Task, AgentLog, AgentRole, TaskStatus, TaskType, Metric, IntegrationConfig 
} from './types';
import { classifyTaskWithGemini, makeDecisionWithGemini, executeTaskWithGemini } from './services/geminiService';
import { streamService } from './services/streamService';
import { Plus, Play, RotateCcw, FileText, Check, Bot, AlertTriangle, Inbox, Sun, Moon, Search, Sliders, Trash2, Link2, MessageSquare, Mail, Wifi, X, Loader2 } from 'lucide-react';

const INITIAL_TASK: Task = {
  id: 'task-1',
  source: 'SLACK',
  rawContent: "Hey OpsPilot, we need a PRD for the new 'Dark Mode' feature for the mobile app. It needs to support system preferences and have a toggle in settings. Priority is High.",
  sender: 'Sarah (Product Lead)',
  timestamp: Date.now(),
  status: TaskStatus.PENDING
};

export default function App() {
  const [activeTab, setActiveTab] = useState('inbox');
  const [tasks, setTasks] = useState<Task[]>([INITIAL_TASK]);
  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [logs, setLogs] = useState<AgentLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Integration State
  const [integrations, setIntegrations] = useState<IntegrationConfig[]>([
    { id: 'slack', name: 'Slack', description: 'Listen to engineering and product channels.', isConnected: false },
    { id: 'gmail', name: 'Gmail', description: 'Monitor support and info inboxes.', isConnected: false },
    { id: 'notion', name: 'Notion', description: 'Watch for new pages in Product Workspace.', isConnected: false }
  ]);

  // Auth Modal State
  const [authModal, setAuthModal] = useState<{ isOpen: boolean; integrationId: string | null }>({ isOpen: false, integrationId: null });
  const [authInput, setAuthInput] = useState('');
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  // Theme Effect
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'light') {
      root.classList.add('light-theme');
    } else {
      root.classList.remove('light-theme');
    }
  }, [theme]);

  // API Key Check
  useEffect(() => {
    if (!process.env.API_KEY) {
      setApiKeyMissing(true);
    }
  }, []);

  // Real-time Stream Subscription
  useEffect(() => {
    const unsubscribe = streamService.subscribe((newTask) => {
      setTasks(prev => [newTask, ...prev]);

      // Notify user via a log or toast equivalent
      addLog(AgentRole.INPUT, `Stream Event: New signal from ${newTask.source}`, 'ACTION', { id: newTask.id });
    });
    return () => unsubscribe();
  }, []);

  // Update Stream Service when integrations change
  useEffect(() => {
    integrations.forEach(integration => {
      if (integration.isConnected) {
        streamService.activateConnector(integration.id);
      } else {
        streamService.deactivateConnector(integration.id);
      }
    });
  }, [integrations]);

  // Dynamic Metrics Calculation
  const metrics: Metric[] = useMemo(() => {
    const total = tasks.length;
    if (total === 0) return [
      { label: 'Task Success Rate', value: '0%', trend: 'neutral' },
      { label: 'Avg. Response Time', value: '0s', trend: 'neutral' },
      { label: 'Active Connectors', value: 0, trend: 'neutral' },
      { label: 'Actions Executed', value: 0, trend: 'neutral' },
    ];

    const completed = tasks.filter(t => t.status === TaskStatus.COMPLETED).length;
    const rate = Math.round((completed / total) * 100);
    const activeConnectors = integrations.filter(i => i.isConnected).length;

    return [
      { label: 'Task Success Rate', value: `${rate}%`, change: 2.1, trend: 'up' },
      { label: 'Avg. Response Time', value: '1.2s', change: 12, trend: 'up' }, // Mocked for now, hard to calc without start/end times
      { label: 'Active Connectors', value: activeConnectors, change: activeConnectors > 0 ? 100 : 0, trend: 'up' },
      { label: 'Total Volume', value: total, change: 8, trend: 'up' },
    ];
  }, [tasks, integrations]);


  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  const handleConnectClick = (id: string) => {
    const integration = integrations.find(i => i.id === id);
    if (integration?.isConnected) {
      // Disconnect Logic
      setIntegrations(prev => prev.map(int => 
        int.id === id ? { ...int, isConnected: false, connectedAccount: undefined } : int
      ));
      addLog(AgentRole.INPUT, `System: Disconnected ${integration.name} connector.`, 'ACTION');
    } else {
      // Open Auth Modal
      setAuthInput('');
      setAuthModal({ isOpen: true, integrationId: id });
    }
  };

  const confirmConnection = async () => {
    if (!authModal.integrationId || !authInput) return;

    setIsAuthenticating(true);
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    setIntegrations(prev => prev.map(int => 
      int.id === authModal.integrationId 
        ? { ...int, isConnected: true, lastSync: Date.now(), connectedAccount: authInput } 
        : int
    ));

    addLog(AgentRole.INPUT, `System: Successfully connected ${authModal.integrationId} account: ${authInput}`, 'RESULT');

    setIsAuthenticating(false);
    setAuthModal({ isOpen: false, integrationId: null });
  };

  const addLog = (agent: AgentRole, message: string, step: 'THINKING' | 'ACTION' | 'RESULT', data?: any) => {
    const newLog: AgentLog = {
      id: Math.random().toString(36).substring(7),
      timestamp: Date.now(),
      agent,
      message,
      step,
      data
    };
    setLogs(prev => [...prev, newLog]);
  };

  const handleSimulateIncoming = () => {
    const newTask = { ...INITIAL_TASK, id: `task-${Date.now()}`, timestamp: Date.now() };
    setTasks(prev => [newTask, ...prev]);
    setSelectedTaskId(newTask.id);
    addLog(AgentRole.INPUT, `Received new message from ${newTask.source}`, 'ACTION', { content: newTask.rawContent });
  };

  const clearHistory = () => {
    setTasks([]);
    setLogs([]);
    setSelectedTaskId(null);
  };

  const processTask = useCallback(async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task || isProcessing) return;

    setIsProcessing(true);
    setLogs([]); 
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.PROCESSING } : t));

    try {
      addLog(AgentRole.CLASSIFIER, "Analyzing message intent and entities...", 'THINKING');
      const classification = await classifyTaskWithGemini(task.rawContent, task.sender);
      addLog(AgentRole.CLASSIFIER, "Classification complete", 'RESULT', classification);

      const updatedTask = { ...task, ...classification };

      addLog(AgentRole.MEMORY, "Checking context and previous constraints...", 'THINKING');
      await new Promise(r => setTimeout(r, 800)); 
      addLog(AgentRole.MEMORY, "No conflicting blocking constraints found.", 'RESULT');

      addLog(AgentRole.DECISION, "Determining optimal execution path...", 'THINKING');
      const decision = await makeDecisionWithGemini(updatedTask);
      addLog(AgentRole.DECISION, `Decision made: ${decision.action}`, 'ACTION', decision);

      const decidedTask = { ...updatedTask, ...decision };

      if (decidedTask.outputType !== 'NONE') {
        addLog(AgentRole.EXECUTION, `Executing action: ${decision.action}...`, 'ACTION');
        const output = await executeTaskWithGemini(decidedTask);
        decidedTask.outputContent = output;
        addLog(AgentRole.EXECUTION, "Content generated successfully", 'RESULT', { preview: output.substring(0, 100) + '...' });
      } else {
        addLog(AgentRole.EXECUTION, "No content generation required. Updating records.", 'ACTION');
      }

      setTasks(prev => prev.map(t => t.id === taskId ? { ...decidedTask, status: TaskStatus.COMPLETED } : t));
      addLog(AgentRole.MEMORY, "Task lifecycle completed. State updated.", 'RESULT');

    } catch (e) {
      addLog(AgentRole.EXECUTION, "Critical Failure in processing chain", 'RESULT', { error: e });
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.FAILED } : t));
    } finally {
      setIsProcessing(false);
    }
  }, [tasks, isProcessing]);

  // --- VIEW RENDERERS ---

  const renderDashboard = () => (
