              title={item.label}
            >
              <Icon size={20} className="flex-shrink-0" />
              {/* On mobile: Label is visible but maybe hidden on very small screens? Let's keep it visible for the 'tab' feel */}
              <span className={`font-medium text-sm whitespace-nowrap transition-all duration-200 ${
                isCollapsed ? 'md:opacity-0 md:w-0 md:hidden' : 'opacity-100'
