        if (String(err).includes('401')) {
           addLog(AgentRole.INPUT, "Gmail Auth expired. Please reconnect.", 'RESULT');
           setIntegrations(prev => prev.map(i => i.id === 'gmail' ? { ...i, isConnected: false, accessToken: undefined } : i));
        }
