  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      const base64Data = (e.target?.result as string).split(',')[1];

      try {
        // Create session
        const session: DocumentSession = {
          id: Math.random().toString(36).substring(7),
          fileName: file.name,
          fileData: base64Data,
          mimeType: file.type,
          uploadTime: Date.now(),
          insights: '',
          chatHistory: [],
          isAnalyzing: true
        };
        setDocSession(session);

        const effectiveKey = userApiKey || getEnv('API_KEY');
        if (effectiveKey) {
           // Analyze immediately with Real AI
           const insights = await analyzeDocumentWithGemini(effectiveKey, base64Data, file.type);
           setDocSession(prev => prev ? { ...prev, insights, isAnalyzing: false } : null);
        } else {
           // Simulated Analysis
           await new Promise(r => setTimeout(r, 1500));
           setDocSession(prev => prev ? { 
             ...prev, 
             insights: "## Simulated Analysis\n\n(No API Key detected)\n\n**Key Takeaway 1**: The document appears to be valid.\n**Key Takeaway 2**: Content analysis requires a valid Gemini API key to function.\n\nPlease enter your API Key in Settings.", 
             isAnalyzing: false 
           } : null);
        }

      } catch (err) {
        console.error("Upload failed", err);
        setDocSession(null);
      } finally {
        setIsUploading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleDocChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!docChatInput.trim() || !docSession) return;

    const userMsg: ChatMessage = { role: 'user', text: docChatInput, timestamp: Date.now() };

    // 1. Optimistic Update (using functional update to be safe)
    setDocSession(prev => prev ? { 
      ...prev, 
      chatHistory: [...prev.chatHistory, userMsg], 
      isAnalyzing: true 
    } : null);

    setDocChatInput('');

    try {
      const effectiveKey = userApiKey || getEnv('API_KEY');
      let responseText = "";

      if (effectiveKey) {
        // 2. Call API. Use the current session history (which doesn't have the userMsg yet in this closure scope, 
        // effectively, but since we append it manually in chatWithDocument, this is actually what we want 
        // to avoid double prompting).
        responseText = await chatWithDocument(effectiveKey, docSession.fileData, docSession.mimeType, docSession.chatHistory, userMsg.text);
      } else {
        await new Promise(r => setTimeout(r, 1000));
        responseText = "I am running in simulation mode because no API Key was provided. Please go to Settings and enter a valid Gemini API Key to enable real analysis.";
      }

      const botMsg: ChatMessage = { role: 'model', text: responseText, timestamp: Date.now() };

      // 3. Final Update. Use functional update to append botMsg to whatever the LATEST state is 
      // (which includes the optimistic userMsg).
      setDocSession(prev => prev ? { 
        ...prev, 
        chatHistory: [...prev.chatHistory, botMsg],
        isAnalyzing: false 
      } : null);
    } catch (err) {
      console.error("Chat failed", err);
      // On error, we just turn off analyzing, we don't revert the user message.
      setDocSession(prev => prev ? { ...prev, isAnalyzing: false } : null);
    }
  };


